 27→
 28→static void nn_conv_HWC_1x1_single_out_ch_f32(
 29→    const float32_t *in_tensor,
 30→    const int32_t in_tensor_dim_x,
 31→    const int32_t in_tensor_dim_y,
 32→    const int32_t in_tensor_ch,
 33→    const int32_t in_tensor_batch,
 34→    const float32_t *ker_weight,
 35→    float32_t *out_tensor)
 36→{
 37→#if defined(ENA_VEC_ISA) && defined(ENA_VEC_FPU)
 38→    long vl, avl, max_vl;
 39→
 40→    const int dim_size = in_tensor_dim_x * in_tensor_dim_y;
 41→
 42→    NDS_VEC_GET_MAXVL_LMUL(max_vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 43→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 44→    NDS_VEC_VAND_VI(NDS_VEC_V16, NDS_VEC_V16, 0x0); //keep zero for redsum
 45→
 46→    if(in_tensor_ch <= max_vl)
 47→    {
 48→        for (int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
 49→        {
 50→            const float32_t *in_tensor_tmp = in_tensor + i_batch * dim_size * in_tensor_ch;
 51→            float32_t *out_tensor_tmp = out_tensor + i_batch * dim_size;
 52→
 53→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 54→            NDS_VEC_VLE32_V(NDS_VEC_V8, ker_weight);
 55→
 56→            for(int32_t i = 0 ; i < dim_size ; i++)
 57→            {
 58→                NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 59→                NDS_VEC_VLE32_V(NDS_VEC_V0, in_tensor_tmp);
 60→                NDS_VEC_VFMUL_VV(NDS_VEC_V24, NDS_VEC_V0, NDS_VEC_V8);
 61→                NDS_VEC_VFREDSUM_VS(NDS_VEC_V0, NDS_VEC_V24, NDS_VEC_V16);
 62→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 63→                NDS_VEC_VSE32_V(NDS_VEC_V0, out_tensor_tmp);
 64→                in_tensor_tmp += in_tensor_ch;
 65→                out_tensor_tmp++;
 66→            }
 67→        }
 68→    }
 69→    else // in_tensor_ch > max_vl
 70→    {
 71→        for (int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
 72→        {
 73→            const float32_t *in_tensor_tmp = in_tensor + i_batch * dim_size * in_tensor_ch;
 74→            float32_t *out_tensor_tmp = out_tensor + i_batch * dim_size;
 75→
 76→            for(int32_t i = 0 ; i < dim_size ; i++)
 77→            {
 78→                NDS_VEC_VSETVLI(vl, max_vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 79→                NDS_VEC_VAND_VI(NDS_VEC_V24, NDS_VEC_V24, 0x0);
 80→
 81→                const float32_t *ker_weight_tmp = ker_weight;
 82→                avl = in_tensor_ch;
 83→
 84→                while(avl > 0)
 85→                {
 86→                    NDS_VEC_VSETVLI(vl, avl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
 87→                    NDS_VEC_VLE32_V(NDS_VEC_V0, in_tensor_tmp);
 88→                    NDS_VEC_VLE32_V(NDS_VEC_V8, ker_weight_tmp);
 89→                    NDS_VEC_VFMACC_VV(NDS_VEC_V24, NDS_VEC_V0, NDS_VEC_V8);
 90→
 91→                    in_tensor_tmp += vl;
 92→                    ker_weight_tmp += vl;
 93→                    avl -= vl;
 94→                }
 95→
 96→                NDS_VEC_VFREDSUM_VS(NDS_VEC_V0, NDS_VEC_V24, NDS_VEC_V16);
 97→                NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
 98→                NDS_VEC_VSE32_V(NDS_VEC_V0, out_tensor_tmp);
 99→                out_tensor_tmp++;
100→            }
101→        }
102→    }
103→#else
104→    const int dim_size = in_tensor_dim_x * in_tensor_dim_y;
105→
106→    for (int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
107→    {
108→        const float32_t *in_tensor_tmp = in_tensor + i_batch * dim_size * in_tensor_ch;
109→        float32_t *out_tensor_tmp = out_tensor + i_batch * dim_size;
110→
111→        for(int32_t i = 0 ; i < dim_size ; i++)
112→        {
113→            float32_t conv_out_acc = 0;
114→
115→            for (int32_t i_input_ch = 0; i_input_ch < in_tensor_ch; i_input_ch++)
116→            {
117→                conv_out_acc += *in_tensor_tmp * ker_weight[i_input_ch];
118→                in_tensor_tmp++;
119→            }
120→

60→    // calculate the weight contribution
61→    int32_t contri_buf[out_tensor_ch];
62→    const int8_t *pWt = ker_weight;
63→    long vl;
64→    long maxvl_per_vg;
65→    NDS_VEC_VSETVLI(maxvl_per_vg, reg_x0, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
66→    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
67→    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   // const zero for redsum
68→
69→    if (bias != NULL)
70→    {
71→        for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
72→        {
73→            long in_tensor_ch2 = in_tensor_ch;
74→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
75→            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0);     // init the acculators
76→            NDS_VEC_VSETVLI(vl, in_tensor_ch, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
77→            NDS_VEC_VMV_V_I(NDS_VEC_V16, 1);                // const one for vd4dot
78→
79→            while (in_tensor_ch2 >= maxvl_per_vg)
